#include <stdio.h>
#include <stdlib.h>
#include <math.h>

typedef struct {
    int prime;
    int count;
} PrimeFactor;

PrimeFactor prime_factors[100];
int prime_count = 0;

void compute_prime_factors(int number) {
    int divisor = 2;
    while (divisor * divisor <= number) {
        while (number % divisor == 0) {
            int found = 0;
            for (int i = 0; i < prime_count; i++) {
                if (prime_factors[i].prime == divisor) {
                    prime_factors[i].count++;
                    found = 1;
                    break;
                }
            }
            if (!found) {
                prime_factors[prime_count].prime = divisor;
                prime_factors[prime_count].count = 1;
                prime_count++;
            }
            number /= divisor;
        }
        divisor++;
    }
    if (number > 1) {
        int found = 0;
        for (int i = 0; i < prime_count; i++) {
            if (prime_factors[i].prime == number) {
                prime_factors[i].count++;
                found = 1;
                break;
            }
        }
        if (!found) {
            prime_factors[prime_count].prime = number;
            prime_factors[prime_count].count = 1;
            prime_count++;
        }
    }
}

int count_factor_in_factorial(int factor, int factorial_base) {
    int count = 0;
    while (factorial_base > 0) {
        count += factorial_base / factor;
        factorial_base /= factor;
    }
    return count;
}

int main() {
    int n, b;
    scanf("%d %d", &n, &b);
    long long result = 1LL << 60;
    compute_prime_factors(b);
